'use client';

import { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useGSAP } from '@gsap/react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

const vertexShader = `
  uniform float uTime;
  uniform float uProgress; 
  varying vec2 vUv;
  varying float vElevation;

  void main() {
    vUv = uv;
    vec3 pos = position;

    float scrollLength = 10.0; 
    // Map progress 0..1 to the rolling window
    float rollPoint = (uProgress * 1.1 - 0.05) * scrollLength - (scrollLength / 2.0);

    if (pos.x > rollPoint) {
      float distancePastRoll = pos.x - rollPoint;
      float radius = 0.5; 
      float angle = distancePastRoll / radius;
      
      pos.x = rollPoint + sin(angle) * radius;
      pos.z = radius - cos(angle) * radius;
      pos.z += distancePastRoll * 0.01; 
    }
    
    float wave = sin(pos.x * 2.0 + uTime) * 0.05;
    pos.y += wave;

    vElevation = pos.z;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
  }
`;

const fragmentShader = `
  uniform float uTime;
  varying vec2 vUv;
  varying float vElevation;

  // --- NOISE FUNCTIONS ---
  float hash(float n) { return fract(sin(n) * 1e4); }
  float hash(vec2 p) { return fract(1e4 * sin(17.0 * p.x + p.y * 0.1) * (0.1 + abs(sin(p.y * 13.0 + p.x)))); }

  float noise(vec2 x) {
      vec2 i = floor(x);
      vec2 f = fract(x);
      float a = hash(i);
      float b = hash(i + vec2(1.0, 0.0));
      float c = hash(i + vec2(0.0, 1.0));
      float d = hash(i + vec2(1.0, 1.0));
      vec2 u = f * f * (3.0 - 2.0 * f);
      return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
  }

  float fbm(vec2 x) {
      float v = 0.0;
      float a = 0.5;
      vec2 shift = vec2(100);
      // Rotate to reduce axial bias
      mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.50));
      for (int i = 0; i < 5; ++i) {
          v += a * noise(x);
          x = rot * x * 2.0 + shift;
          a *= 0.5;
      }
      return v;
  }

  void main() {
    vec3 paperColor = vec3(0.98, 0.97, 0.95); // Bright paper
    vec3 inkColor = vec3(0.1, 0.1, 0.12);     // Dark ink with slight blue tint
    
    // 1. Base Paper Texture (Grain)
    float grain = noise(vUv * 500.0) * 0.05;
    
    // 2. Procedural Landscape (Ink Mountains)
    // Stretch uv.x to make long mountains
    vec2 mountainUv = vUv * vec2(3.0, 8.0); 
    float mountains = fbm(mountainUv);
    
    // Mask mountains to center strip (leave top/bottom white)
    float centerMask = smoothstep(0.1, 0.4, vUv.y) * smoothstep(0.9, 0.6, vUv.y);
    
    // Threshold to create "ink blots" instead of clouds
    float ink = smoothstep(0.45, 0.65, mountains) * centerMask;
    
    // Add some "fog" near the bottom of mountains
    float fog = smoothstep(0.4, 0.3, vUv.y) * mountains * 0.3;
    
    vec3 color = mix(paperColor - grain, inkColor, ink);
    color = mix(color, vec3(0.9, 0.9, 0.95), fog); // Add bluish fog

    // 3. Shadow from curling
    // Darken the rolled part slightly
    color -= vElevation * 0.15;

    gl_FragColor = vec4(color, 1.0);
  }
`;

export default function ScrollModel() {
  const mesh = useRef<THREE.Mesh>(null);
  
  const progressRef = useRef({ value: 0 });

  const uniforms = useMemo(
    () => ({
      uTime: { value: 0 },
      uProgress: { value: 0 },
    }),
    []
  );

  useGSAP(() => {
    const tl = gsap.timeline({
      scrollTrigger: {
        trigger: "body", 
        start: "top top",
        end: "bottom bottom",
        scrub: 1, 
      }
    });

    tl.to(progressRef.current, {
      value: 1,
      ease: "none"
    });

  }, []);

  useFrame((state) => {
    if (mesh.current) {
      const material = mesh.current.material as THREE.ShaderMaterial;
      material.uniforms.uTime.value = state.clock.getElapsedTime();
      material.uniforms.uProgress.value = progressRef.current.value;
    }
  });

  return (
    <mesh ref={mesh} rotation={[0, 0, 0]}>
      <planeGeometry args={[10, 4, 128, 64]} /> 
      <shaderMaterial
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
        side={THREE.DoubleSide}
        transparent
      />
    </mesh>
  );
}
